import React, { useState, useEffect, useRef } from 'react';

const DropdownMenu = ({ onSelect }) => {
  const [isOpen, setIsOpen] = useState(false);
  const dropdownRef = useRef(null);
  const menuItemsRef = useRef([]);

  const toggleDropdown = () => {
    setIsOpen(prev => !prev);
  };

  const handleMenuItemClick = (option) => {
    onSelect(option);
    setIsOpen(false);
    dropdownRef.current.querySelector('button').focus(); // Return focus to toggle button
  };

  const handleKeyDown = (event) => {
    if (event.key === 'Escape') {
      setIsOpen(false);
      dropdownRef.current.querySelector('button').focus();
    } else if ((event.key === 'ArrowDown' || event.key === 'ArrowUp') && !isOpen) {
      setIsOpen(true);
      event.preventDefault(); // Prevent page scroll
    } else if (event.key === 'Enter' || event.key === ' ') {
      if (!isOpen) {
        setIsOpen(true);
        event.preventDefault();
      }
    }
  };

  const handleMenuItemKeyDown = (event, index) => {
    if (event.key === 'ArrowDown') {
      event.preventDefault();
      const nextIndex = (index + 1) % menuItemsRef.current.length;
      menuItemsRef.current[nextIndex].focus();
    } else if (event.key === 'ArrowUp') {
      event.preventDefault();
      const prevIndex = (index - 1 + menuItemsRef.current.length) % menuItemsRef.current.length;
      menuItemsRef.current[prevIndex].focus();
    } else if (event.key === 'Escape') {
      setIsOpen(false);
      dropdownRef.current.querySelector('button').focus();
    } else if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      // Simulate item activation
      handleMenuItemClick(options[index]);
    } else if (event.key === 'Tab') {
      // Allow default tab behavior to move focus out of the dropdown
      setIsOpen(false);
    }
  };

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
        setIsOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  useEffect(() => {
    if (isOpen) {
      // Focus first item when dropdown opens
      // Use requestAnimationFrame to ensure elements are rendered before focusing
      requestAnimationFrame(() => {
        menuItemsRef.current[0]?.focus();
      });
    }
  }, [isOpen]);

  const options = ['Option A', 'Option B', 'Option C', 'Option D'];

  return (
    <div ref={dropdownRef} style={{ position: 'relative', display: 'inline-block' }}>
      <button
        onClick={toggleDropdown}
        onKeyDown={handleKeyDown}
        aria-haspopup="true"
        aria-expanded={isOpen}
        style={{
          padding: '8px 12px',
          cursor: 'pointer',
          backgroundColor: '#007bff',
          color: 'white',
          border: 'none',
          borderRadius: '4px'
        }}
      >
        Select an Option
      </button>
      {isOpen && (
        <ul
          role="menu"
          style={{
            position: 'absolute',
            listStyle: 'none',
            padding: 0,
            margin: '5px 0 0 0',
            border: '1px solid #ccc',
            backgroundColor: 'white',
            minWidth: '150px',
            zIndex: 100,
            boxShadow: '0 2px 5px rgba(0,0,0,0.2)',
            borderRadius: '4px'
          }}
        >
          {options.map((option, index) => (
            <li key={index} role="none">
              <button
                ref={el => menuItemsRef.current[index] = el}
                role="menuitem"
                onClick={() => handleMenuItemClick(option)}
                onKeyDown={(e) => handleMenuItemKeyDown(e, index)}
                tabIndex={0} // Make button focusable
                style={{
                  width: '100%',
                  padding: '10px 12px',
                  border: 'none',
                  background: 'none',
                  textAlign: 'left',
                  cursor: 'pointer',
                  outline: 'none',
                  whiteSpace: 'nowrap',
                  boxSizing: 'border-box'
                }}
                onFocus={(e) => e.target.style.backgroundColor = '#f0f0f0'}
                onBlur={(e) => e.target.style.backgroundColor = 'white'}
              >
                {option}
              </button>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
};

export default DropdownMenu;

