import { Component, HostListener } from '@angular/core';

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: system-ui, sans-serif; padding: 40px; text-align: center">
      <h2>Dropdown Menu</h2>
      <div style="display:inline-block; position:relative; text-align:left">
        <button
          (click)="toggle($event)"
          style="padding:10px 16px; border-radius:8px; border:1px solid #c7c7d1; background:#fff; cursor:pointer; min-width:200px; display:flex; justify-content:space-between; gap:8px">
          <span>{{ selected || 'Select an option' }}</span>
          <span>{{ open ? '\u25B4' : '\u25BE' }}</span>
        </button>
        <ul
          *ngIf="open"
          style="position:absolute; left:0; right:0; margin-top:6px; padding:4px; list-style:none; background:#fff; border:1px solid #e5e5ea; border-radius:8px; box-shadow:0 8px 24px rgba(0,0,0,0.12); z-index:10">
          <li
            *ngFor="let item of items"
            (click)="select(item)"
            [style.background]="item === selected ? '#eef2ff' : 'transparent'"
            style="padding:8px 12px; border-radius:6px; cursor:pointer">
            {{ item }}
          </li>
        </ul>
      </div>
      <p style="margin-top:20px; color:#666">Selected: <strong>{{ selected || 'none' }}</strong></p>
    </div>
  `,
})
export class AppComponent {
  open = false;
  selected = '';
  items = ['Profile', 'Settings', 'Billing', 'Sign out'];

  toggle(e: MouseEvent) {
    e.stopPropagation();
    this.open = !this.open;
  }

  select(item: string) {
    this.selected = item;
    this.open = false;
  }

  @HostListener('document:click')
  onDocClick() {
    this.open = false;
  }

  @HostListener('document:keydown.escape')
  onEscape() {
    this.open = false;
  }
}
